def f(expr):
    def evaluate(expr):
        stack = []
        num = 0
        sign = '+'
        i = 0
        while i < len(expr):
            c = expr[i]
            if c.isdigit():
                num = num * 10 + int(c)
            if c == '(':
                j = i
                bal = 1
                while i + 1 < len(expr) and bal != 0:
                    i += 1
                    if expr[i] == '(':
                        bal += 1
                    if expr[i] == ')':
                        bal -= 1
                num = evaluate(expr[j+1:i])
            if (not c.isdigit() and c != ' ') or i == len(expr) - 1:
                if sign == '+':
                    stack.append(num)
                elif sign == '-':
                    stack.append(-num)
                elif sign == '*':
                    stack.append(stack.pop() * num)
                sign = c
                num = 0
            i += 1
        return sum(stack)
    return evaluate(expr)
